const input = $('Start').item.json;
const result = $input.first().json;
input.contexto = {
  STATUS_OS_ATIVA: null,
  OS_ATUAL: null,
  VEICULO: null,
  LISTA_TAREFAS: result.lista_tarefas || [],
  AGENDA_ATUAL: []
};
function buildContextoTexto(ctx) {
  var fmt = function(val) { return val == null ? 'null' : (typeof val === 'object' ? JSON.stringify(val) : String(val)); };
  var fmtArr = function(val) { return (!val || val.length === 0) ? '[]' : JSON.stringify(val); };
  return '[STATUS_OS_ATIVA]\n' + fmt(ctx.STATUS_OS_ATIVA)
    + '\n\n[OS_ATUAL]\n' + fmt(ctx.OS_ATUAL)
    + '\n\n[VEICULO]\n' + fmt(ctx.VEICULO)
    + '\n\n[LISTA_TAREFAS]\n' + fmtArr(ctx.LISTA_TAREFAS)
    + '\n\n[AGENDA_ATUAL]\n' + fmtArr(ctx.AGENDA_ATUAL);
}
input.contexto_texto = buildContextoTexto(input.contexto);
return [{ json: input }];

